// Convert AI response → Sanity Portable Text + build the create mutation
const resp = $input.first().json;
const args = JSON.parse(resp.choices[0].message.tool_calls[0].function.arguments);

const rid = () => Math.random().toString(36).slice(2, 14);

const body = args.sections.map(s => ({
  _type: 'block',
  _key: rid(),
  style: s.type === 'h2' ? 'h2' : s.type === 'h3' ? 'h3' : 'normal',
  markDefs: [],
  children: [{ _type: 'span', _key: rid(), text: s.text, marks: [] }]
}));

// Schedule for tomorrow 9am IST (= 03:30 UTC)
const pub = new Date();
pub.setUTCDate(pub.getUTCDate() + 1);
pub.setUTCHours(3, 30, 0, 0);

const doc = {
  _type: 'post',
  _id: 'drafts.' + rid() + rid(),
  title: args.title,
  slug: { _type: 'slug', current: args.slug },
  excerpt: args.excerpt,
  tags: args.tags,
  body,
  publishedAt: pub.toISOString()
};

return [{ json: { mutations: [{ create: doc }], _meta: { title: args.title, slug: args.slug } } }];
